def load_cards(self):
    with rx.session() as session:
        self.cards = session.exec(select(Card).order_by(Card.position)).all()

class State(rx.State):
    """The app state."""
    cards: List[Card] = []

    def load_cards(self):
        with rx.session() as session:
            self.cards = session.exec(select(Card).order_by(Card.position)).all()
